  useEffect(()=>{if(!pl?.is_playing||!pl?.item)return;const id=setInterval(()=>setPl(p=>(p&&p.is_playing&&p.item)?{...p,progress_ms:Math.min((p.progress_ms||0)+1000,p.item.duration_ms||0)}:p),1000);return()=>clearInterval(id)},[pl?.is_playing,pl?.item?.id]);

  useEffect(()=>{const id=pl?.item?.album?.id;if(!id||!tok){setAlbumTks([]);return}let live=true;sp(`/albums/${id}/tracks?limit=50`,tok).then(r=>{if(live)setAlbumTks(r?.items||[])}).catch(()=>{if(live)setAlbumTks([])});return()=>{live=false}},[pl?.item?.album?.id,tok]);
  useEffect(()=>{const aid=pl?.item?.artists?.[0]?.id,curAlb=pl?.item?.album?.id;if(!aid||!tok){setArtAlbums([]);return}let live=true;sp(`/artists/${aid}/albums?include_groups=album,single&limit=40`,tok).then(r=>{if(!live)return;const seen=new Set();const list=(r?.items||[]).filter(al=>{if(!al||al.id===curAlb)return false;const k=(al.name||"").toLowerCase().replace(/\s*\(.*?\)\s*/g,"").replace(/\s*-\s*(single|ep|remaster.*)$/i,"").trim();if(seen.has(k))return false;seen.add(k);return true}).sort((a,b)=>{const g=x=>x.album_type==="album"?0:1;return g(a)-g(b)||String(b.release_date||"").localeCompare(String(a.release_date||""))}).slice(0,8);setArtAlbums(list)}).catch(()=>{if(live)setArtAlbums([])});return()=>{live=false}},[pl?.item?.artists?.[0]?.id,pl?.item?.album?.id,tok]);
  useEffect(()=>{if(!evoData||evoMode!=="genres"||!tok)return;let live=true;(async()=>{const seen={},list=[];["long","medium","short","recent"].forEach(k=>((evoData[k]?.artists)||[]).forEach(a=>{if(a.id&&!seen[a.id]){seen[a.id]=1;list.push(a)}}));const todo=list.filter(a=>!mbCache.current[a.id]);if(!todo.length){setEvoGen({done:list.length,total:list.length,loading:false});return}setEvoGen({done:list.length-todo.length,total:list.length,loading:true});for(const a of todo){if(!live)break;const r=await fetchMB(a.name);mbCache.current[a.id]=r||{genres:[],country:null,countryCode:null};setMb(prev=>({...prev,[a.id]:mbCache.current[a.id]}));setEvoGen(g=>({done:Math.min(g.done+1,g.total),total:g.total,loading:true}));await new Promise(r=>setTimeout(r,1200))}if(live)setEvoGen(g=>({...g,loading:false}))})();return()=>{live=false}},[evoData,evoMode,tok]);

  const cmd=async a=>{try{if(a==="play")await sp("/me/player/play",tok,{method:"PUT"});else if(a==="pause")await sp("/me/player/pause",tok,{method:"PUT"});else if(a==="next")await sp("/me/player/next",tok,{method:"POST"});else if(a==="prev")await sp("/me/player/previous",tok,{method:"POST"});else if(a==="shuffle")await sp(`/me/player/shuffle?state=${!pl?.shuffle_state}`,tok,{method:"PUT"});else if(a==="repeat"){const m=["off","context","track"];await sp(`/me/player/repeat?state=${m[(m.indexOf(pl?.repeat_state||"off")+1)%3]}`,tok,{method:"PUT"})}setTimeout(()=>sp("/me/player",tok,{},0).then(setPl).catch(()=>{}),300)}catch{}};
