          {tT[0]&&<Card onClick={()=>play(tT[0].uri)} style={{display:"flex",alignItems:"center",gap:MQ?12:18,position:"relative",overflow:"hidden"}}><div style={{position:"absolute",inset:0,background:`radial-gradient(220px 140px at 0% 50%,rgba(184,255,102,0.10),transparent 70%)`,pointerEvents:"none"}} />{tT[0].album?.images?.[0]&&<img src={tT[0].album.images[0].url} alt="" style={{width:MQ?62:94,height:MQ?62:94,borderRadius:MQ?10:14,objectFit:"cover",boxShadow:"0 8px 24px rgba(0,0,0,0.5)",flexShrink:0}} />}<div style={{position:"relative",minWidth:0}}><Lbl>Titre #1</Lbl><div style={{fontSize:MQ?17:21,fontWeight:600,fontFamily:FD,letterSpacing:"-0.02em",lineHeight:1.05,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{tT[0].name}</div><div style={{color:C.mut,fontSize:MQ?12:11,marginTop:4}}>{(tT[0].artists||[]).map(a=>a.name).join(", ")}</div></div></Card>}
