          <SC label="Durée moy." value={fmt(avgDur)} sub="par titre · voir la répartition" icon="📏" onClick={()=>{const buckets=[["< 2 min",0,120],["2–3 min",120,180],["3–4 min",180,240],["4–5 min",240,300],["5–6 min",300,360],["6–8 min",360,480],["8 min +",480,1e9]];const secs=(tT||[]).map(t=>(t.duration_ms||0)/1000).filter(s=>s>0);const counts=buckets.map(([l,lo,hi])=>({l,n:secs.filter(s=>s>=lo&&s<hi).length}));const mx=Math.max(1,...counts.map(c=>c.n));pushDrill("Répartition par durée",<div>{counts.map((c,i)=><div key={i} style={{display:"flex",alignItems:"center",gap:12,padding:"7px 0"}}><span style={{color:C.mut,width:92,fontSize:MQ?14:12,flexShrink:0}}>{c.l}</span><div style={{flex:1,height:18,background:"rgba(255,255,255,0.05)",borderRadius:9}}><div style={{height:18,width:`${(c.n/mx)*100}%`,background:`linear-gradient(90deg,${C.grn},${C.grnB})`,borderRadius:9,minWidth:c.n?18:0}} /></div><span style={{color:C.txt,width:32,textAlign:"right",fontFamily:"monospace",fontSize:MQ?14:12}}>{c.n}</span></div>)}<p style={{color:C.mut,fontSize:MQ?13:11,marginTop:12}}>Sur tes {secs.length} top titres · moyenne {fmt(avgDur)}.</p></div>)}} />
          {diversity!==null&&<SC label="Diversité" value={`${diversity}/100`} sub="100 = éclaté · voir les genres" icon="🎛" onClick={()=>pushDrill("Genres — genre principal par artiste",<div><p style={{color:C.mut,fontSize:MQ?14:12,marginBottom:12}}>Diversité {diversity}/100, calculée sur le <b style={{color:C.txt}}>genre principal</b> de chacun de tes {tA.length} artistes.</p>{divGenres.map((g,i)=><div key={g.name} style={{display:"flex",alignItems:"center",gap:10,padding:"6px 0",borderBottom:`1px solid ${C.brd}`}}><span style={{color:C.mut,width:24,textAlign:"right",fontFamily:"monospace",fontSize:MQ?13:11}}>{i+1}</span><div style={{flex:1,color:C.txt,fontSize:MQ?15:13}}>{tc(g.name)}</div><span style={{color:C.acc,fontFamily:"monospace",fontSize:MQ?13:11}}>{g.count}</span></div>)}</div>)} />}
          {freshness!==null&&<SC label="Fraîcheur" value={`${freshness}%`} sub="sorties ≤ 3 ans (top titres) · voir" icon="🌱" onClick={()=>pushDrill("Fraîcheur — tes top titres par année",<div><p style={{color:C.mut,fontSize:MQ?14:12,marginBottom:12}}>{freshList.filter(o=>o.recent).length} titre(s) sortis il y a ≤ 3 ans sur tes {freshList.length} top titres datés. Clique pour lire.</p>{freshList.slice().sort((a,b)=>b.y-a.y).map(({t,y,recent})=><div key={t.id} onClick={()=>play(t.uri)} style={{display:"flex",alignItems:"center",gap:10,padding:"7px 0",borderBottom:`1px solid ${C.brd}`,cursor:"pointer",opacity:recent?1:0.55}}>{t.album?.images?.[0]&&<img src={t.album.images[t.album.images.length>1?1:0].url} alt="" style={{width:36,height:36,borderRadius:5,flexShrink:0}} />}<div style={{flex:1,minWidth:0}}><div style={{color:C.txt,fontSize:MQ?14:12,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{t.name}</div><div style={{color:C.mut,fontSize:MQ?12:10,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{(t.artists||[]).map(a=>a.name).join(", ")}</div></div><span style={{color:recent?C.grnB:C.mut,fontFamily:"monospace",fontSize:MQ?13:11}}>{y}</span></div>)}</div>)} />}
          {allG.length>0&&<SC label="Genre #1" value={tc(allG[0].name)} sub={`${allG[0].count} artistes`} icon="🎨" onClick={()=>openDrill(tc(allG[0].name),abg[allG[0].name]||[])} />}
          {allC.length>0&&<SC label="Pays #1" value={allC[0].name} sub={`${allC[0].count} artistes`} icon="🌍" onClick={()=>openDrill(allC[0].name,abc[allC[0].name]||[])} />}
          <SC label="Genres" value={allG.length} icon="🏷" onClick={drillGenres} />
